import React, { useState, useEffect } from 'react';
import axios from 'axios';

const UserManagement = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/users');
      setUsers(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải users:', error);
      setLoading(false);
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    if (window.confirm(`Xác nhận đổi quyền thành ${newRole.toUpperCase()}?`)) {
      try {
        await axios.put(`http://localhost:5000/api/admin/users/${userId}/role`, { role: newRole });
        alert('Cập nhật thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Thất bại'));
      }
    }
  };

  const handleDeleteUser = async (userId) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa vĩnh viễn người dùng này?')) {
      try {
        await axios.delete(`http://localhost:5000/api/admin/users/${userId}`);
        alert('Đã xóa thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Xóa thất bại'));
      }
    }
  };

  if (loading) return <div style={{ padding: '20px', textAlign: 'center' }}>🔄 Đang tải dữ liệu...</div>;

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <h1 style={{ marginBottom: '20px' }}>👥 Quản lý người dùng</h1>
      
      {/* Thống kê nhanh */}
      <div style={{ display: 'flex', gap: '20px', marginBottom: '30px' }}>
        <div style={cardStyle}>
          <span style={{ fontSize: '24px' }}>📊</span>
          <div>
            <div style={{ color: '#666', fontSize: '14px' }}>Tổng số</div>
            <div style={{ fontSize: '20px', fontWeight: 'bold' }}>{users.length}</div>
          </div>
        </div>
        <div style={cardStyle}>
          <span style={{ fontSize: '24px' }}>👑</span>
          <div>
            <div style={{ color: '#666', fontSize: '14px' }}>Quản trị</div>
            <div style={{ fontSize: '20px', fontWeight: 'bold' }}>{users.filter(u => u.role === 'admin').length}</div>
          </div>
        </div>
      </div>

      {/* Bảng dữ liệu */}
      <div style={{ overflowX: 'auto', boxShadow: '0 0 10px rgba(0,0,0,0.1)', borderRadius: '8px' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
          <thead style={{ backgroundColor: '#f4f4f4' }}>
            <tr>
              <th style={thStyle}>ID</th>
              <th style={thStyle}>Họ tên</th>
              <th style={thStyle}>Email / SĐT</th>
              <th style={thStyle}>Vai trò</th>
              <th style={{ ...thStyle, textAlign: 'center' }}>Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {users.map(user => (
              <tr key={user.id} style={{ borderBottom: '1px solid #eee' }}>
                <td style={tdStyle}>#{user.id}</td>
                <td style={tdStyle}><strong>{user.fullname}</strong></td>
                <td style={tdStyle}>
                  <div>📧 {user.email}</div>
                  <div style={{ fontSize: '12px', color: '#888' }}>📞 {user.phone || 'N/A'}</div>
                </td>
                <td style={tdStyle}>
                  <select
                    value={user.role}
                    onChange={(e) => handleRoleChange(user.id, e.target.value)}
                    style={{
                      padding: '5px 10px',
                      borderRadius: '15px',
                      border: '1px solid #ddd',
                      backgroundColor: user.role === 'admin' ? '#fff3cd' : '#d4edda',
                      fontWeight: 'bold'
                    }}
                  >
                    <option value="user">Người dùng</option>
                    <option value="admin">Quản trị</option>
                  </select>
                </td>
                <td style={{ ...tdStyle, textAlign: 'center' }}>
                  <button 
                    onClick={() => handleDeleteUser(user.id)}
                    disabled={user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1}
                    style={{
                      padding: '6px 12px',
                      backgroundColor: 'transparent',
                      border: '1px solid #ff4d4f',
                      color: '#ff4d4f',
                      borderRadius: '4px',
                      cursor: 'pointer',
                      opacity: (user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1) ? 0.5 : 1
                    }}
                  >
                    🗑️ Xóa
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

// CSS nội bộ
const cardStyle = {
  flex: 1,
  padding: '15px',
  background: '#fff',
  borderRadius: '8px',
  display: 'flex',
  alignItems: 'center',
  gap: '15px',
  border: '1px solid #eee'
};

const thStyle = { padding: '12px', textAlign: 'left', fontSize: '14px', color: '#555' };
const tdStyle = { padding: '12px', fontSize: '14px' };

export default UserManagement;
